55	const PROCESSING_FEE = 5;
56	const BLOCK_SIZE = 3;
57	const RUNE_BLOCK_PRICE = 60;
58	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
59	  sword: 100,
60	  amulet: 60,
61	  staff: 80,
62	  potion: 40,
63	  rune: 25,
64	  moonstone: 25,
65	};
66	
67	const basePremium = (item: Item): number =>
68	  BASE_PREMIUM_BY_TYPE[item.type] ?? 0;
69	
70	const isRuneBlock = (items: Item[]): boolean =>
71	  items.length === BLOCK_SIZE && items.every((it) => it.type === "rune");
72	
73	const sumBasePremiums = (items: Item[]): number =>
74	  items.reduce((sum, item) => sum + basePremium(item), 0);
75	
76	const componentsTotal = (items: Item[]): number =>
77	  isRuneBlock(items) ? RUNE_BLOCK_PRICE : sumBasePremiums(items);
78	
79	const quotePremium = (items: Item[]): number =>
80	  componentsTotal(items) + PROCESSING_FEE;
81	
82	export const processScenario = (scenario: Scenario): ScenarioOutput => {
83	  const step = scenario.steps[0] as QuoteStep;
84	  return { results: [{ premium: quotePremium(step.items) }] };
85	};
